package com.example.demo.spring.common.exception;

import com.example.demo.spring.common.response.ApiResponse;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.TypeMismatchException;
import org.springframework.http.HttpStatus;
import org.springframework.http.converter.HttpMessageNotReadableException;
import org.springframework.web.ErrorResponse;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;
import org.springframework.web.servlet.mvc.support.DefaultHandlerExceptionResolver;

/**
 * 全局异常处理，统一处理业务异常与系统异常。
 * 打印日志并返回失败信息。
 * @see DefaultHandlerExceptionResolver
 */
@RestControllerAdvice
@Slf4j
public class GlobalExceptionHandler {

    /**
     * 处理业务异常并返回统一响应。
     * @param e 业务异常
     * @return 失败响应
     */
    @ExceptionHandler(BusinessException.class)
    public ApiResponse<?> handleBusinessException(BusinessException e) {
        log.warn("业务异常 {} {}", e.getMessage(), e.getStackTrace()[0]);
        return ApiResponse.fail(e.getMessage());
    }

    /**
     * 处理未捕获异常并返回统一响应。
     * @param t 异常信息
     * @return 失败响应
     */
    @ExceptionHandler(Throwable.class)
    public ApiResponse<?> handleThrowable(Throwable t) {
        if (t instanceof ErrorResponse errorResponse && errorResponse.getStatusCode().is4xxClientError()) {
            HttpStatus httpStatus = HttpStatus.valueOf(errorResponse.getStatusCode().value());
            log.warn("客户端异常 {} {}", httpStatus.getReasonPhrase(), t.getMessage());
            return ApiResponse.fail(httpStatus.getReasonPhrase());
        }
        if (t instanceof TypeMismatchException || t instanceof HttpMessageNotReadableException) {
            log.warn("客户端异常 {}", t.getMessage());
            return ApiResponse.fail(t.getMessage());
        }
        log.error("服务端异常", t);
        return ApiResponse.fail("服务端异常:" + t.getMessage());
    }
}

package com.example.demo.spring.common.request;

import lombok.extern.slf4j.Slf4j;
import org.aspectj.lang.ProceedingJoinPoint;
import org.aspectj.lang.annotation.Around;
import org.aspectj.lang.annotation.Aspect;
import org.aspectj.lang.annotation.Pointcut;
import org.springframework.core.Ordered;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;
import tools.jackson.databind.json.JsonMapper;

/**
 * 日志切面，记录请求参数、结果和时间
 */
@Component
@Aspect
@Order(Ordered.HIGHEST_PRECEDENCE)
@Slf4j
public class LogAspect {
    private final JsonMapper jsonMapper;

    /**
     * 日志切面构造
     * @param jsonMapper JsonMapper
     */
    public LogAspect(JsonMapper jsonMapper) {
        this.jsonMapper = jsonMapper;
    }

    /**
     * 切入点：匹配所有 Controller/RestController 类中的方法
     * @see org.springframework.stereotype.Controller
     * @see org.springframework.web.bind.annotation.RestController
     */
    @Pointcut("@within(org.springframework.stereotype.Controller)" +
            "|| @within(org.springframework.web.bind.annotation.RestController)")
    public void classPointcut() {
        // 切入点定义，无实际代码
    }

    /**
     * 切入点：匹配所有请求映射注解的方法
     * @see org.springframework.web.bind.annotation.RequestMapping
     * @see org.springframework.web.bind.annotation.GetMapping
     * @see org.springframework.web.bind.annotation.PostMapping
     * @see org.springframework.web.bind.annotation.PutMapping
     * @see org.springframework.web.bind.annotation.DeleteMapping
     */
    @Pointcut("@annotation(org.springframework.web.bind.annotation.RequestMapping)" +
            "|| @annotation(org.springframework.web.bind.annotation.GetMapping)" +
            "|| @annotation(org.springframework.web.bind.annotation.PostMapping)" +
            "|| @annotation(org.springframework.web.bind.annotation.PutMapping)" +
            "|| @annotation(org.springframework.web.bind.annotation.DeleteMapping)")
    public void methodPointcut() {
        // 切入点定义，无实际代码
    }

    /**
     * 记录请求参数、响应结果与耗时
     * @param joinPoint 切点
     * @return 调用结果
     * @throws Throwable 执行异常
     */
    @Around("classPointcut() && methodPointcut()")
    public Object logAround(ProceedingJoinPoint joinPoint) throws Throwable {
        long startNanoTime = System.nanoTime();

        // 记录请求参数和结果
        log.info("Request: {}", jsonMapper.writeValueAsString(joinPoint.getArgs()));
        Object result = joinPoint.proceed();
        log.info("Response: {}", jsonMapper.writeValueAsString(result));

        // 记录时间
        long endNanoTime = System.nanoTime();
        long duration = endNanoTime - startNanoTime;
        if (duration > 1_000_000_000) {
            log.warn("Request took too long: {} ms", (int) (duration / 1_000_000));
        } else {
            log.info("Request took: {} ms", (int) (duration / 1_000_000));
        }

        // 返回
        return result;
    }
}

