package com.example.demo.spring.common.request;

import jakarta.servlet.*;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.MDC;
import org.springframework.core.Ordered;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;
import org.springframework.util.StringUtils;

import java.io.IOException;
import java.util.Enumeration;
import java.util.UUID;

/**
 * Trace过滤器，用于给每个请求添加TraceID，可通过RequestUtil获取
 * TraceID用于日志跟踪，帮助定位请求的处理路径
 * @see RequestUtil
 */
@Component
@Order(Ordered.HIGHEST_PRECEDENCE)
public class TraceFilter implements Filter {
    public static final String TRACE_ID_KEY = "traceid";

    /**
     * 注入 traceId 并透传至响应头
     * @param servletRequest 请求
     * @param servletResponse 响应
     * @param filterChain 过滤器链
     * @throws ServletException 过滤异常
     * @throws IOException IO异常
     */
    @Override
    public void doFilter(ServletRequest servletRequest, ServletResponse servletResponse, FilterChain filterChain) throws ServletException, IOException {
        if (!(servletRequest instanceof HttpServletRequest httpServletRequest) || !(servletResponse instanceof HttpServletResponse httpServletResponse)) {
            return;
        }

        try {
            // 从请求头获取 TraceID
            String traceId = "";
            Enumeration<String> headerNames = httpServletRequest.getHeaderNames();
            if (headerNames != null) {
                while (headerNames.hasMoreElements()) {
                    String name = headerNames.nextElement();
                    if (name.toLowerCase().contains("trace-id") || name.toLowerCase().contains("traceid")) {
                        String value = httpServletRequest.getHeader(name);
                        if (StringUtils.hasText(value)) {
                            traceId = value.replace("-", "");
                            break;
                        }
                    }
                }
            }

            // 没有则随机生成
            if (!StringUtils.hasText(traceId)) {
                traceId = UUID.randomUUID().toString().replace("-", "");
            }

            // 设置 TraceID
            MDC.put(TRACE_ID_KEY, traceId);
            httpServletRequest.setAttribute(TRACE_ID_KEY, traceId);
            httpServletResponse.setHeader("X-Trace-Id", traceId);

            // 继续处理请求
            filterChain.doFilter(servletRequest, servletResponse);
        } finally {
            // 移除 TraceID
            MDC.remove(TRACE_ID_KEY);
        }
    }
}

package com.example.demo.spring.common.request;

import com.example.demo.spring.common.response.ApiResponse;
import jakarta.servlet.*;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.MDC;
import org.springframework.core.Ordered;
import org.springframework.core.annotation.Order;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Component;
import org.springframework.util.StringUtils;
import tools.jackson.databind.json.JsonMapper;

import java.io.IOException;
import java.nio.charset.StandardCharsets;

/**
 * User过滤器，用于校验用户信息，并给每个请求添加UserID，可通过RequestUtil获取
 * UserID用于日志跟踪，帮助定位用户请求的处理路径
 * @see RequestUtil
 */
@Component
@Order(Ordered.HIGHEST_PRECEDENCE + 1)
public class UserFilter implements Filter {
    public static final String USER_ID_KEY = "userid";

    private final JsonMapper jsonMapper;

    /**
     * 用户过滤器构造
     * @param jsonMapper JsonMapper
     */
    public UserFilter(JsonMapper jsonMapper) {
        this.jsonMapper = jsonMapper;
    }

    /**
     * 校验用户并注入 userId
     * @param servletRequest 请求
     * @param servletResponse 响应
     * @param filterChain 过滤器链
     * @throws IOException IO异常
     * @throws ServletException 过滤异常
     */
    @Override
    public void doFilter(ServletRequest servletRequest, ServletResponse servletResponse, FilterChain filterChain) throws IOException, ServletException {
        if (!(servletRequest instanceof HttpServletRequest httpServletRequest) || !(servletResponse instanceof HttpServletResponse httpServletResponse)) {
            return;
        }

        try {
            // 获取token
            String token = httpServletRequest.getHeader("Authorization");

            // 模拟校验token
            if (!StringUtils.hasText(token)) {
                httpServletResponse.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                httpServletResponse.setContentType(MediaType.APPLICATION_JSON_VALUE);
                httpServletResponse.setCharacterEncoding(StandardCharsets.UTF_8);
                httpServletResponse.getWriter().write(jsonMapper.writeValueAsString(ApiResponse.fail("未登录或登录已过期")));
                return;
            }
            Long userId = 12345L;

            // 注入请求信息
            MDC.put(USER_ID_KEY, userId.toString());
            httpServletRequest.setAttribute(USER_ID_KEY, userId);

            // 继续处理请求
            filterChain.doFilter(servletRequest, servletResponse);
        } finally {
            // 移除 TraceID
            MDC.remove(USER_ID_KEY);
        }
    }
}

package com.example.demo.spring.common.response;

import lombok.Data;

import java.util.List;
import java.util.Map;

/**
 * API接口响应封装类
 * @param <T> 响应数据类型
 */
@Data
public class ApiResponse<T> {
    private Boolean success;
    private String message;
    private Long current;
    private Long size;
    private Long total;
    private T data;
    private Map<String, Object> extra;

    /**
     * 返回成功响应（无数据）
     * @param <T> 响应数据类型
     * @return 成功响应
     */
    public static <T> ApiResponse<T> success() {
        ApiResponse<T> apiResponse = new ApiResponse<>();
        apiResponse.setSuccess(true);
        apiResponse.setMessage("success");
        return apiResponse;
    }

    /**
     * 返回成功响应（带数据）
     * @param data 响应数据
     * @param <T> 响应数据类型
     * @return 成功响应
     */
    public static <T> ApiResponse<T> success(T data) {
        ApiResponse<T> apiResponse = success();
        apiResponse.setData(data);
        if (data instanceof List<?> list) {
            apiResponse.setCurrent(1L);
            apiResponse.setSize((long) list.size());
            apiResponse.setTotal((long) list.size());
        }
        return apiResponse;
    }

    /**
     * 返回成功响应（带分页信息）
     * @param data 响应数据
     * @param current 当前页
     * @param size 每页大小
     * @param total 总数
     * @param <T> 响应数据类型
     * @return 成功响应
     */
    public static <T> ApiResponse<T> success(T data, Long current, Long size, Long total) {
        ApiResponse<T> apiResponse = success();
        apiResponse.setData(data);
        apiResponse.setCurrent(current);
        apiResponse.setSize(size);
        apiResponse.setTotal(total);
        return apiResponse;
    }

    /**
     * 返回失败响应
     * @param message 失败原因
     * @param <T> 响应数据类型
     * @return 失败响应
     */
    public static <T> ApiResponse<T> fail(String message) {
        ApiResponse<T> apiResponse = new ApiResponse<>();
        apiResponse.setSuccess(false);
        apiResponse.setMessage(message);
        return apiResponse;
    }
}

package com.example.demo.spring.config;

import org.slf4j.MDC;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.task.AsyncTaskExecutor;
import org.springframework.core.task.SimpleAsyncTaskExecutor;
import org.springframework.scheduling.concurrent.ThreadPoolTaskExecutor;
import org.springframework.web.context.request.RequestAttributes;
import org.springframework.web.context.request.RequestContextHolder;

import java.util.Map;
import java.util.concurrent.ThreadPoolExecutor;

/**
 * 线程池配置类：包含虚拟线程池和普通线程池
 * 注意：虚拟线程池只有在JDK21及以后才使用
 */
@Configuration
public class ExecutorConfig {

    /**
     * 虚拟线程池
     * @return 虚拟线程执行器
     */
    @Bean
    public AsyncTaskExecutor virtualExecutor() {
        SimpleAsyncTaskExecutor asyncTaskExecutor = new SimpleAsyncTaskExecutor();
        asyncTaskExecutor.setVirtualThreads(true);
        asyncTaskExecutor.setThreadNamePrefix("vtask-");
        asyncTaskExecutor.setTaskDecorator(task -> {
            // 获取Request和MDC环境
            RequestAttributes attributes = RequestContextHolder.getRequestAttributes();
            Map<String, String> contextMap = MDC.getCopyOfContextMap();
            return () -> {
                try {
                    // 设置环境
                    if (attributes != null) {
                        RequestContextHolder.setRequestAttributes(attributes);
                    }
                    if (contextMap != null) {
                        MDC.setContextMap(contextMap);
                    }
                    task.run();
                } finally {
                    // 清理环境
                    RequestContextHolder.resetRequestAttributes();
                    MDC.clear();
                }
            };
        });
        return asyncTaskExecutor;
    }

    /**
     * 普通线程池
     * @return 普通线程执行器
     */
    @Bean
    public AsyncTaskExecutor threadExecutor() {
        ThreadPoolTaskExecutor asyncTaskExecutor = new ThreadPoolTaskExecutor();
        asyncTaskExecutor.setVirtualThreads(false);
        asyncTaskExecutor.setThreadNamePrefix("task-");
        asyncTaskExecutor.setRejectedExecutionHandler(new ThreadPoolExecutor.CallerRunsPolicy());
        asyncTaskExecutor.setQueueCapacity(0);
        asyncTaskExecutor.setTaskDecorator(task -> {
            // 获取Request和MDC环境
            RequestAttributes attributes = RequestContextHolder.getRequestAttributes();
            Map<String, String> contextMap = MDC.getCopyOfContextMap();
            return () -> {
                try {
                    // 设置环境
                    if (attributes != null) {
                        RequestContextHolder.setRequestAttributes(attributes);
                    }
                    if (contextMap != null) {
                        MDC.setContextMap(contextMap);
                    }
                    task.run();
                } finally {
                    // 清理环境
                    RequestContextHolder.resetRequestAttributes();
                    MDC.clear();
                }
            };
        });
        asyncTaskExecutor.initialize();
        return asyncTaskExecutor;
    }
}

package com.example.demo.spring.config;

import io.netty.channel.ChannelOption;
import io.netty.handler.timeout.ReadTimeoutHandler;
import io.netty.handler.timeout.WriteTimeoutHandler;
import lombok.extern.slf4j.Slf4j;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.http.client.ReactorClientHttpRequestFactory;
import org.springframework.http.client.reactive.ReactorClientHttpConnector;
import org.springframework.http.codec.json.JacksonJsonDecoder;
import org.springframework.http.codec.json.JacksonJsonEncoder;
import org.springframework.http.converter.json.JacksonJsonHttpMessageConverter;
import org.springframework.web.client.RestClient;
import org.springframework.web.reactive.function.client.WebClient;
import reactor.netty.http.client.HttpClient;
import reactor.netty.resources.ConnectionProvider;
import tools.jackson.databind.json.JsonMapper;

import java.time.Duration;
import java.util.concurrent.TimeUnit;

/**
 * RestClient和WebClient配置类
 * 配置连接池，超时时间，编解码器，默认请求头，日志打印
 */
@Configuration
@Slf4j
public class HttpClientConfig {
    // 连接池连接数
    private static final int MAX_CONNECTION = 100;
    // 连接超时时间
    private static final int CONNECT_TIMEOUT_MILLIS = 2000;
    // 整个响应超时时间
    private static final int RESPONSE_TIMEOUT_MILLIS = 10_000;
    // 读取超时时间（两次读取间隔）
    private static final int READ_TIMEOUT_MILLIS = 10_000;
    // 写入超时时间（两次写入间隔）
    private static final int WRITE_TIMEOUT_MILLIS = 10_000;

    /**
     * HTTP 连接池配置
     * @return 连接池
     */
    @Bean
    public ConnectionProvider connectionProvider() {
        return ConnectionProvider
                .builder("http-client")
                // 最大连接数
                .maxConnections(MAX_CONNECTION)
                .build();
    }

    /**
     * HTTP 客户端配置
     * @param connectionProvider 连接池
     * @return HttpClient
     */
    @Bean
    public HttpClient httpClient(ConnectionProvider connectionProvider) {
        return HttpClient.create(connectionProvider)
                // 连接超时
                .option(ChannelOption.CONNECT_TIMEOUT_MILLIS, CONNECT_TIMEOUT_MILLIS)
                // 整个响应超时
                .responseTimeout(Duration.ofMillis(RESPONSE_TIMEOUT_MILLIS))
                // 读写超时
                .doOnConnected(connection -> connection
                        .addHandlerLast(new ReadTimeoutHandler(READ_TIMEOUT_MILLIS, TimeUnit.MILLISECONDS))
                        .addHandlerLast(new WriteTimeoutHandler(WRITE_TIMEOUT_MILLIS, TimeUnit.MILLISECONDS)));
    }

    /**
     * RestClient 构建器
     * @param httpClient HttpClient
     * @param jsonMapper JsonMapper
     * @return RestClient.Builder
     */
    @Bean
    public RestClient.Builder restClientBuilder(HttpClient httpClient, JsonMapper jsonMapper) {
        return RestClient.builder()
                // 请求工厂
                .requestFactory(new ReactorClientHttpRequestFactory(httpClient))
                // 编解码器
                .configureMessageConverters(converters ->
                        converters.registerDefaults().withJsonConverter(new JacksonJsonHttpMessageConverter(jsonMapper))
                )
                // 默认请求头
                .defaultHeader(HttpHeaders.CONTENT_TYPE, MediaType.APPLICATION_JSON_VALUE)
                .defaultHeader(HttpHeaders.ACCEPT, MediaType.ALL_VALUE)
                // 日志拦截器
                .requestInterceptor((request, body, execution) -> {
                    log.info("Rest client: {} {}", request.getMethod(), request.getURI());
                    return execution.execute(request, body);
                });
    }

    /**
     * RestClient 实例
     * @param restClientBuilder 构建器
     * @return RestClient
     */
    @Bean
    public RestClient restClient(RestClient.Builder restClientBuilder) {
        return restClientBuilder.build();
    }

    /**
     * WebClient 构建器
     * @param httpClient HttpClient
     * @param jsonMapper JsonMapper
     * @return WebClient.Builder
     */
    @Bean
    public WebClient.Builder webClientBuilder(HttpClient httpClient, JsonMapper jsonMapper) {
        return WebClient.builder()
                // 请求工厂
                .clientConnector(new ReactorClientHttpConnector(httpClient))
                // 编解码器
                .codecs(configurer -> configurer.defaultCodecs().jacksonJsonEncoder(new JacksonJsonEncoder(jsonMapper)))
                .codecs(configurer -> configurer.defaultCodecs().jacksonJsonDecoder(new JacksonJsonDecoder(jsonMapper)))
                // 默认请求头
                .defaultHeader(HttpHeaders.CONTENT_TYPE, MediaType.APPLICATION_JSON_VALUE)
                .defaultHeader(HttpHeaders.ACCEPT, MediaType.ALL_VALUE)
                // 日志过滤器
                .filter((request, next) -> {
                    log.info("Web client: {} {}", request.method(), request.url());
                    return next.exchange(request);
                });
    }

    /**
     * WebClient 实例
     * @param webClientBuilder 构建器
     * @return WebClient
     */
    @Bean
    public WebClient webClient(WebClient.Builder webClientBuilder) {
        return webClientBuilder.build();
    }
}

package com.example.demo.spring.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import tools.jackson.databind.ext.javatime.deser.LocalDateTimeDeserializer;
import tools.jackson.databind.ext.javatime.ser.LocalDateTimeSerializer;
import tools.jackson.databind.json.JsonMapper;
import tools.jackson.databind.module.SimpleModule;

import java.text.SimpleDateFormat;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.TimeZone;

/**
 * Jackson JsonMapper 配置类
 * 配置LocalDateTime日期时间序列化格式
 */
@Configuration
public class JacksonConfig {
    // 时间格式化模板
    public static final String DATE_TIME_PATTERN = "yyyy-MM-dd HH:mm:ss";
    // 时区（东八区）
    public static final String TIME_ZONE = "GMT+8";

    /**
     * JsonMapper 配置
     * @return JsonMapper 实例
     */
    @Bean
    public JsonMapper jsonMapper() {
        // Java 8时间模块
        SimpleModule simpleModule = new SimpleModule();
        simpleModule.addSerializer(LocalDateTime.class, new LocalDateTimeSerializer(DateTimeFormatter.ofPattern(DATE_TIME_PATTERN)));
        simpleModule.addDeserializer(LocalDateTime.class, new LocalDateTimeDeserializer(DateTimeFormatter.ofPattern(DATE_TIME_PATTERN)));
        return JsonMapper.builder()
                // 注册Java 8时间模块（必须）配置LocalDateTime的序列化/反序列化器（核心解决时间格式问题）
                .addModule(simpleModule)
                // 配置java.util.Date时区和格式（等价于yml中的time-zone:GMT+8和date-format）
                .defaultTimeZone(TimeZone.getTimeZone(TIME_ZONE))
                .defaultDateFormat(new SimpleDateFormat(DATE_TIME_PATTERN))
                .build();
    }
}
